#include <iostream>
using namespace std;

int main() {
    int grade;
    cin >> grade;

    if (grade > 89) {
        cout << "A" << endl;
    } else if (grade > 79) {
        cout << "B" << endl;
    } else if (grade > 69) {
        cout << "C" << endl;
    } else if (grade > 59) {
        cout << "D" << endl;
    } else {
        cout << "F" << endl;
    }

    return 0;
}
